game_info.concept:
{
  "game_name": "Cut the Rope",
  "genre": "Puzzle",
  "core_mechanics": {
    "player_actions": [
      {
        "action": "Cut Rope",
        "trigger": "Mouse drag (or touch swipe) across a rope segment.",
        "description": "When the player's pointer drags over a rope, the rope segment is removed from the physics simulation, allowing the connected bodies to move freely under gravity. A tolerance for 'swiping' near a rope should be implemented."
      },
      {
        "action": "Activate Mechanism",
        "trigger": "Mouse click (or touch tap) on an interactive object (e.g., air cushion).",
        "description": "When the player clicks/taps on a specific interactive object, its effect is triggered (e.g., an air cushion puffs, applying a force to nearby candy)."
      }
    ],
    "gameplay_rules_systems": [
      {
        "system": "Physics Engine (Matter.js)",
        "rules": "All dynamic game objects (candy) are subject to gravity and collision physics. Ropes are implemented as constraints between bodies. Environmental elements (walls, spikes) are static bodies. Air cushions apply impulse/force. Bubbles apply buoyancy and can be 'popped' (removed)."
      },
      {
        "system": "Candy Movement",
        "rules": "The 'candy' is a primary Matter.js rigid body. Its movement is entirely dictated by the physics engine (gravity, collisions, rope cuts, environmental forces). The player does not directly control its movement, only influences it."
      },
      {
        "system": "Rope Mechanics",
        "rules": "Ropes are Matter.js constraints (e.g., `Matter.Constraint.create`). They connect the candy to static points or other bodies. When cut, the corresponding constraint is removed from the Matter.js world. A visual line represents the rope."
      },
      {
        "system": "Star Collection",
        "rules": "Gold stars are static trigger-only bodies. When the candy collides with a star, the star is marked as collected, provides points, and is visually removed from the level. Up to 3 stars per level."
      },
      {
        "system": "Win Condition Trigger",
        "rules": "Collision between the candy body and the Om Nom monster's mouth hitbox triggers level completion."
      },
      {
        "system": "Lose Condition Trigger",
        "rules": "Collision between the candy body and a hazard (spikes) or the candy falling below a certain Y-coordinate (off-screen) triggers level failure."
      }
    ],
    "state_tracking": [
      "Current Level Index (e.g., `currentLevel = 0`)",
      "Candy position, velocity, rotation (`Matter.Body` properties)",
      "Existence and state of each rope (active/cut)",
      "Collected status of each star in the current level (`true`/`false` boolean array)",
      "Activation state of interactive mechanisms (e.g., `airCushionActive = true`)",
      "Current score for the level and total cumulative score",
      "High score for each level and overall high score",
      "Game state (MENU, PLAYING, PAUSED, WIN_LEVEL, LOSE_LEVEL)",
      "Total stars collected across all levels (for level unlocking)"
    ]
  },
  "visual_elements": {
    "game_objects": [
      {
        "name": "Candy",
        "representation": "Red circular shape with a white swirl pattern (p5.js `ellipse()` and `arc()`/`bezier()` for swirl). Rendered directly over its Matter.js `circle` body. Diameter: ~40-60 pixels.",
        "animations_effects": "Rotates and moves according to physics. Small 'jiggle' on collision. 'Eat' animation when reaching Om Nom (fade out, Om Nom mouth close)."
      },
      {
        "name": "Rope",
        "representation": "Thin brown line connecting two Matter.js bodies (p5.js `line()`). Thickness: ~2-4 pixels.",
        "animations_effects": "Snaps visually (disappears instantly or with a quick fade/particle effect) when cut."
      },
      {
        "name": "Om Nom",
        "representation": "Stylized green monster head (p5.js `ellipse()` for head, `triangle()` for horns, `arc()` for mouth). Mouth is a specific target area. Size: ~80-100 pixels wide.",
        "animations_effects": "Mouth opens slightly when candy is near, closes and expresses happiness on successful candy delivery."
      },
      {
        "name": "Gold Star",
        "representation": "Small yellow 5-point star shape (p5.js custom `beginShape()`/`vertex()` drawing). Diameter: ~20-30 pixels.",
        "animations_effects": "Flashes/twinkles briefly then fades out when collected. Small particle burst on collection."
      },
      {
        "name": "Air Cushion / Puff",
        "representation": "Rectangular base (p5.js `rect()`) with a circular/oval 'puff' area above it. Base color: gray/blue.",
        "animations_effects": "Puff animation (growing/shrinking white/light blue `ellipse()` or sprite sequence) when activated, indicating force application."
      },
      {
        "name": "Bubble",
        "representation": "Transparent light blue circular shape (p5.js `ellipse()` with `alpha` transparency, `noFill()` for outline).",
        "animations_effects": "Attaches to candy, makes it float. 'Pop' animation (quick expansion, then disappear with small particle effect) when clicked or hit by a sharp object."
      },
      {
        "name": "Spikes / Hazards",
        "representation": "Triangular or jagged shapes (p5.js `triangle()` or custom `beginShape()`). Color: dark gray/black with red tips.",
        "animations_effects": "None specific, potentially a 'shatter' effect on candy collision."
      },
      {
        "name": "Walls / Static Objects",
        "representation": "Rectangular or polygonal shapes (p5.js `rect()` or custom `beginShape()`). Color: various, e.g., brown for wood, grey for stone.",
        "animations_effects": "None."
      }
    ],
    "ui_elements": [
      {
        "name": "Score Display",
        "representation": "Text string 'SCORE: [current_score]' in top-right corner. Font: clear, readable (e.g., Arial, 24px).",
        "animations_effects": "Updates dynamically. Points awarded may briefly animate upwards from the source (e.g., star)."
      },
      {
        "name": "Stars Collected Display",
        "representation": "Icons of stars (filled yellow for collected, outline gray for uncollected) in the top-center. e.g., '\u2b50 \u2b50 \u2606'. Font: large, clear (e.g., 36px).",
        "animations_effects": "Filled stars appear instantly when collected."
      },
      {
        "name": "Level Indicator",
        "representation": "Text string 'Level [current_level_number]' in the top-left corner. Font: clear, readable (e.g., Arial, 24px).",
        "animations_effects": "Changes on level transition."
      },
      {
        "name": "Menu Buttons",
        "representation": "Rectangular buttons with text labels (e.g., 'Play', 'Restart', 'Next Level'). Color: distinct, e.g., blue background, white text.",
        "animations_effects": "Hover/click feedback (color change, slight scale)."
      },
      {
        "name": "Game Over / Win Screen",
        "representation": "Overlay text ('LEVEL COMPLETE!', 'LEVEL FAILED!') with score/star summary and action buttons. Semi-transparent background overlay.",
        "animations_effects": "Fade in/out, possibly a celebratory animation for win screen."
      }
    ],
    "animations_effects_general": [
      "Level transition screen (fade out/in, slide, or simple text overlay for 'Loading Next Level').",
      "Candy physics: smooth movement, rotation, bouncing on collisions.",
      "Particle effects for key events: star collection, bubble pop, candy destruction."
    ]
  },
  "control_scheme": {
    "mouse_touch_controls": [
      {
        "action": "Cut Rope",
        "trigger": "Mouse drag (or touch swipe) over a rope."
      },
      {
        "action": "Activate Mechanism",
        "trigger": "Mouse click (or touch tap) on an interactive object (e.g., air cushion, bubble)."
      }
    ],
    "keyboard_controls": [
      {
        "key": "ArrowLeft",
        "action": "Navigate left in menus (e.g., level select) or cycle through options. (No direct gameplay action)."
      },
      {
        "key": "ArrowRight",
        "action": "Navigate right in menus (e.g., level select) or cycle through options. (No direct gameplay action)."
      },
      {
        "key": "Space",
        "action": "Activate 'Magic Finger' superpower (if implemented) or confirm menu selection. In-game: Applies a temporary impulse to candy, simulating the Magic Finger's effect, once per level. This is a simplification of the superpower concept for keyboard users."
      },
      {
        "key": "Z",
        "action": "Restart current level. (No direct equivalent in original, but useful for puzzle games)."
      },
      {
        "key": "Escape",
        "action": "Pause/unpause game, or go back from current menu/screen to previous."
      }
    ],
    "special_combinations": []
  },
  "game_states": {
    "states": [
      "START_MENU",
      "LEVEL_SELECT",
      "PLAYING",
      "PAUSED",
      "WIN_LEVEL",
      "LOSE_LEVEL"
    ],
    "transitions": [
      {
        "from": "START_MENU",
        "to": "PLAYING",
        "trigger": "Player clicks 'Play' button (starts Level 1)."
      },
      {
        "from": "START_MENU",
        "to": "LEVEL_SELECT",
        "trigger": "Player clicks 'Level Select' button."
      },
      {
        "from": "LEVEL_SELECT",
        "to": "PLAYING",
        "trigger": "Player selects and clicks on an unlocked level."
      },
      {
        "from": "LEVEL_SELECT",
        "to": "START_MENU",
        "trigger": "Player clicks 'Back' or 'Main Menu' button."
      },
      {
        "from": "PLAYING",
        "to": "PAUSED",
        "trigger": "Player presses 'Escape' key or clicks pause button."
      },
      {
        "from": "PLAYING",
        "to": "WIN_LEVEL",
        "trigger": "Candy successfully collides with Om Nom's mouth."
      },
      {
        "from": "PLAYING",
        "to": "LOSE_LEVEL",
        "trigger": "Candy falls off-screen or collides with a hazard (spikes)."
      },
      {
        "from": "PAUSED",
        "to": "PLAYING",
        "trigger": "Player clicks 'Resume' button or presses 'Escape' again."
      },
      {
        "from": "PAUSED",
        "to": "PLAYING",
        "trigger": "Player clicks 'Restart Level' button (reloads current level)."
      },
      {
        "from": "PAUSED",
        "to": "START_MENU",
        "trigger": "Player clicks 'Main Menu' button."
      },
      {
        "from": "WIN_LEVEL",
        "to": "PLAYING",
        "trigger": "Player clicks 'Next Level' button (if next level exists and is unlocked)."
      },
      {
        "from": "WIN_LEVEL",
        "to": "PLAYING",
        "trigger": "Player clicks 'Replay Level' button (restarts current level)."
      },
      {
        "from": "WIN_LEVEL",
        "to": "LEVEL_SELECT",
        "trigger": "Player clicks 'Level Select' button."
      },
      {
        "from": "LOSE_LEVEL",
        "to": "PLAYING",
        "trigger": "Player clicks 'Restart Level' button (reloads current level)."
      },
      {
        "from": "LOSE_LEVEL",
        "to": "LEVEL_SELECT",
        "trigger": "Player clicks 'Level Select' button."
      }
    ]
  },
  "win_conditions": "The player wins the level when the candy rigid body successfully collides with the designated Om Nom 'mouth' trigger area. This concludes the level, tallies stars collected, and calculates the level score.",
  "lose_conditions": "The player loses the level under two primary conditions: 1) The candy rigid body falls below the designated bottom-of-screen boundary (e.g., y-coordinate > `height + buffer`). 2) The candy rigid body collides with a designated 'hazard' body (e.g., spikes).",
  "scoring_system": {
    "actions_points": [
      {
        "action": "Deliver Candy to Om Nom",
        "points": "+500 points",
        "description": "Awarded upon successful completion of the level."
      },
      {
        "action": "Collect a Gold Star",
        "points": "+100 points per star",
        "description": "Awarded instantly when candy collides with and collects a star (up to 3 per level)."
      },
      {
        "action": "3-Star Completion Bonus",
        "points": "+50 bonus points",
        "description": "Awarded if all three gold stars are collected in a single level attempt."
      },
      {
        "action": "Time Bonus",
        "points": "+10 points per second (up to 100 points max)",
        "description": "Awarded based on how quickly the level is completed. For simplification, if completed within top 25% of a 'par time', +100 points. If in top 50%, +50 points. Otherwise +0 points."
      }
    ],
    "bonus_multipliers": "Only the '3-Star Completion Bonus' is implemented. No explicit score multipliers.",
    "high_score_system": "Yes. The highest score achieved for each individual level is stored locally (using `localStorage`). An overall total high score (sum of best scores across all levels) is also tracked. This allows players to replay levels to improve their scores.",
    "score_display": "The current level's score will be displayed in the top-right corner of the game canvas, formatted as 'SCORE: [current_score]'. During the `WIN_LEVEL` state, the final score and stars collected for the level will be prominently displayed.",
    "score_affect_gameplay": "No direct effect on gameplay. Score primarily serves as a metric for player achievement and is used for the high score system. Stars collected, however, are a prerequisite for unlocking subsequent levels."
  },
  "level_system": {
    "num_levels": 5,
    "level_progression_rule": "The player advances to the next level upon successfully completing the current level. Subsequent levels within a 'box' (group of levels) unlock based on collecting a sufficient number of stars from previous levels. For this simplified implementation, the next level unlocks immediately upon completion if enough stars are collected (e.g., one star required to proceed).",
    "level_transition_display": "Upon completing a level, a 'Level Complete!' screen will appear, showing the stars collected for that level, the score achieved, and options to 'Next Level', 'Replay', or 'Level Select'. A simple fade-out/fade-in animation will occur when loading the next level.",
    "level_indicator": "A text display 'Level [Current_Level_Number]' will be shown in the top-left corner of the game screen during `PLAYING` state.",
    "levels": [
      {
        "name": "Level 1: Introduction to Ropes",
        "difficulty": "Very Easy",
        "difference": "Introduces the fundamental mechanic of cutting a single rope to deliver candy. Simple trajectory, minimal obstacles.",
        "elements": "Candy, one rope, Om Nom directly below. One star on the direct path. No hazards or interactive elements."
      },
      {
        "name": "Level 2: Double Rope Drop",
        "difficulty": "Easy",
        "difference": "Requires the player to cut two ropes strategically or in sequence to achieve a swinging motion, introducing basic timing.",
        "elements": "Candy, two ropes (e.g., one holding candy, another further along its path), Om Nom to the side. Two stars, requiring a swing to collect both."
      },
      {
        "name": "Level 3: Air Cushion Introduction",
        "difficulty": "Medium",
        "difference": "Introduces an interactive environmental element (air cushion) that needs player activation, adding a 'tapping' mechanic and changing candy trajectory.",
        "elements": "Candy, ropes, Om Nom, an air cushion. Three stars, one requiring activation of the air cushion to reach. Simple walls/floor."
      },
      {
        "name": "Level 4: Bubble Ascent & Pop",
        "difficulty": "Medium-Hard",
        "difference": "Introduces floating mechanics with bubbles and a simple hazard (spikes), requiring timing to pop the bubble strategically to avoid danger.",
        "elements": "Candy, ropes, Om Nom positioned high. A bubble generator that attaches a bubble to the candy. Spikes on the ascent path. Three stars, one high up, one requiring careful bubble pop."
      },
      {
        "name": "Level 5: Combined Challenge",
        "difficulty": "Hard",
        "difference": "Combines multiple mechanics (ropes, air cushions, bubbles) in a complex sequence, demanding precise timing and puzzle-solving. Introduces more intricate level geometry.",
        "elements": "Candy, multiple ropes, Om Nom in a difficult-to-reach location. One air cushion, one bubble. Multiple stars requiring specific sequencing of cuts and activations. Potentially a small moving platform or a movable block."
      }
    ]
  },
  "simplifications": [
    "**Number of Levels/Boxes**: Reduced from '17 boxes containing 425 hand-designed levels' to 5 distinct levels for the initial implementation, demonstrating core mechanics and progression.",
    "**Graphical Fidelity**: Simplified visual elements. Instead of detailed sprites and textures, p5.js drawing primitives (circles, rectangles, lines, custom shapes) will be used for all game objects and UI.",
    "**Superpowers**: The 'Magic Finger' superpower is simplified to a single, limited-use 'apply impulse' action triggered by the 'Space' key, or may be omitted in the initial implementation to focus on core physics puzzles.",
    "**Level Design Complexity**: Level layouts are less intricate than typical Cut the Rope levels, focusing on clear demonstrations of each mechanic before combining them. No complex gear mechanisms or elaborate contraptions are included beyond basic physics interactions.",
    "**Audio**: No specific audio system is detailed; assume basic sound effects (e.g., rope cut, star collected, win/lose chime) will be added if scope allows, but not a core part of this spec.",
    "**Monetization/In-App Purchases**: All references to 'superpowers available' (likely paid in original) are removed or simplified to a free, limited-use mechanic.",
    "**Tutorials/Onboarding**: Implicitly simplified by the 'Introduction to Ropes' level; no explicit tutorial overlay system is specified.",
    "**Localization**: Not considered; all text will be in English."
  ],
  "implementation_notes": "The game should be implemented using Matter.js for all physics-based interactions (rigid bodies, constraints, collisions, forces) and p5.js for rendering all visual elements, handling user input (mouse/touch events for cutting and tapping, keyboard for menus/actions), and managing game states. Level data should be structured in a clear, easily parsed format (e.g., an array of JavaScript objects or separate JSON files per level). LocalStorage will be used to persist high scores and player progress (stars collected per level, unlocked levels). A robust collision detection system using Matter.js events (`Events.on(engine, 'collisionStart', handler)`) will be crucial for managing star collection, win/lose conditions, and hazard interactions. The score display and level indicator must always be visible on screen during active gameplay, adhering to the specified positions and formats."
}
